"use strict";(self.webpackChunkhalt_website=self.webpackChunkhalt_website||[]).push([[94760],{44777:e=>{e.exports=JSON.parse('{"tag":{"label":"ferret health","permalink":"/docs/tags/ferret-health","allTagsPath":"/docs/tags","count":10,"items":[{"id":"Ferrets/illnesses-and-conditions/adrenal-disease","title":"Adrenal Gland Disease in Ferrets","description":"An in-depth guide to adrenal gland disease in ferrets, a common and serious condition characterized by hair loss, discussing its causes, signs, diagnosis, and treatment options.","permalink":"/docs/Ferrets/illnesses-and-conditions/adrenal-disease"},{"id":"Ferrets/illnesses-and-conditions/common-health-issues","title":"Common Health Issues in Ferrets","description":"An overview of the most common health issues affecting pet ferrets, with a strong emphasis on cancers like adrenal disease, insulinoma, and lymphoma, as well as heart disease and GI obstructions.","permalink":"/docs/Ferrets/illnesses-and-conditions/common-health-issues"},{"id":"Ferrets/health-and-wellness/dental-health","title":"Dental Health in Ferrets","description":"A guide to dental health in ferrets, covering common issues like fractured teeth and tartar buildup, and outlining the importance of preventative care, including diet and tooth brushing.","permalink":"/docs/Ferrets/health-and-wellness/dental-health"},{"id":"Ferrets/health-and-wellness/eye-and-vision-issues","title":"Eye & Vision Issues in Ferrets","description":"A guide to common eye and vision issues in ferrets, discussing their naturally poor eyesight and common age-related problems like cataracts and retinal atrophy.","permalink":"/docs/Ferrets/health-and-wellness/eye-and-vision-issues"},{"id":"Ferrets/health-and-wellness/gi-health","title":"Gastrointestinal (GI) Health in Ferrets","description":"A guide to gastrointestinal (GI) health in ferrets, covering their unique digestive system and common issues like foreign body obstructions, vomiting, diarrhea, and ECE.","permalink":"/docs/Ferrets/health-and-wellness/gi-health"},{"id":"Ferrets/illnesses-and-conditions/heart-disease","title":"Heart Disease in Ferrets","description":"A guide to heart disease in ferrets, a common condition in middle-aged and older animals, covering the signs of congestive heart failure, diagnosis, and medical management.","permalink":"/docs/Ferrets/illnesses-and-conditions/heart-disease"},{"id":"Ferrets/illnesses-and-conditions/insulinoma","title":"Insulinoma in Ferrets","description":"An in-depth guide to insulinoma in ferrets, a common pancreatic cancer that causes dangerously low blood sugar, covering the signs, emergency care, diagnosis, and treatment.","permalink":"/docs/Ferrets/illnesses-and-conditions/insulinoma"},{"id":"Ferrets/illnesses-and-conditions/lymphoma","title":"Lymphoma in Ferrets","description":"An in-depth guide to lymphoma, the most common cancer in ferrets, covering its different forms (juvenile and adult), signs, diagnosis, and chemotherapy treatment.","permalink":"/docs/Ferrets/illnesses-and-conditions/lymphoma"},{"id":"Ferrets/health-and-wellness/parasites","title":"Parasites in Ferrets","description":"A guide to common parasites affecting ferrets, including ear mites, fleas, and the serious threat of heartworm disease, as well as internal parasites like coccidia.","permalink":"/docs/Ferrets/health-and-wellness/parasites"},{"id":"Ferrets/health-and-wellness/respiratory-issues","title":"Respiratory Issues in Ferrets","description":"A guide to respiratory issues in ferrets, covering their unique susceptibility to the human influenza virus, as well as other causes of respiratory distress like pneumonia and heart disease.","permalink":"/docs/Ferrets/health-and-wellness/respiratory-issues"}],"unlisted":false}}')}}]);